// Obyekt destrukturizasiyası sınağı
const phone = {
  brand: 'Samsung',
  model: 'Galaxy S20',
  price: 800
};

// Destrukturizasiya
const { brand, model, price } = phone;
console.log(brand); // Samsung
console.log(model); // Galaxy S20
console.log(price); // 800

// Fərqli dəyişən adları və varsayılan dəyər
const { brand: phoneBrand, color = 'Black' } = phone;
console.log(phoneBrand); // Samsung
console.log(color); // Black

// Funksiya ilə destrukturizasiya
function describePhone({ brand, model }) {
  return brand + ' ' + model;
}
console.log(describePhone(phone)); // Samsung Galaxy S20

