// Simple destructuring
const person = {
  name: 'Ali',
  age: 25
};

const { name, age } = person;
console.log(name); // Ali
console.log(age); // 25

// Different variable names
const car = {
  brand: 'Honda',
  model: 'Civic'
};

const { brand: carBrand, model: carModel } = car;
console.log(carBrand); // Honda
console.log(carModel); // Civic

// Default values
const book = {
  title: 'JavaScript Basics'
};

const { title, pages = 100 } = book;
console.log(title); // JavaScript Basics
console.log(pages); // 100

// Destructuring in function parameters
const user = {
  username: 'Veli',
  email: 'veli@example.com'
};

function showUser({ username, email }) {
  return username + ' (' + email + ')';
}

console.log(showUser(user)); // Veli (veli@example.com)

// Error-prone example
const laptop = {
  brand: 'Dell',
  price: 1000
};

// Error: Incorrect property name
const { brand, cost } = laptop;
console.log(cost); // undefined

// Correct approach
const { brand, price } = laptop;
console.log(price); // 1000

// Error: Non-existent property without default value
const { model } = laptop;
console.log(model); // undefined

// Regular property access
const user = {
  name: 'Aysu',
  age: 22
};

const userName = user.name;
const userAge = user.age;
console.log(userName); // Aysu
console.log(userAge); // 22

// Same result with destructuring
const { name, age } = user;
console.log(name); // Aysu
console.log(age); // 22

