// Простая деструктуризация
const person = {
  name: 'Али',
  age: 25
};

const { name, age } = person;
console.log(name); // Али
console.log(age); // 25

// Другие имена переменных
const car = {
  brand: 'Honda',
  model: 'Civic'
};

const { brand: carBrand, model: carModel } = car;
console.log(carBrand); // Honda
console.log(carModel); // Civic

// Значения по умолчанию
const book = {
  title: 'Основы JavaScript'
};

const { title, pages = 100 } = book;
console.log(title); // Основы JavaScript
console.log(pages); // 100

// Деструктуризация в параметрах функции
const user = {
  username: 'Вали',
  email: 'veli@example.com'
};

function showUser({ username, email }) {
  return username + ' (' + email + ')';
}

console.log(showUser(user)); // Вали (veli@example.com)

// Пример с ошибкой
const laptop = {
  brand: 'Dell',
  price: 1000
};

// Ошибка: Неправильное имя свойства
const { brand, cost } = laptop;
console.log(cost); // undefined

// Правильный подход
const { brand, price } = laptop;
console.log(price); // 1000

// Ошибка: Несуществующее свойство без значения по умолчанию
const { model } = laptop;
console.log(model); // undefined

// Обычный доступ к свойствам
const user = {
  name: 'Айсу',
  age: 22
};

const userName = user.name;
const userAge = user.age;
console.log(userName); // Айсу
console.log(userAge); // 22

// Тот же результат с деструктуризацией
const { name, age } = user;
console.log(name); // Айсу
console.log(age); // 22

